                yield return new ValidationResult("Invalid value for PaymentBank, length must be less than 75.", new [] { "PaymentBank" });
            }

            if (this.IssuerRNC != null) {
                // IssuerRNC (string) pattern
                Regex regexIssuerRNC = new Regex(@"^([0-9]{9}|[0-9]{11})$", RegexOptions.CultureInvariant);
                if (!regexIssuerRNC.Match(this.IssuerRNC).Success)
                {
                    yield return new System.ComponentModel.DataAnnotations.ValidationResult("Invalid value for IssuerRNC, must match a pattern of " + regexIssuerRNC, new [] { "IssuerRNC" });
                }
            }

            // IssuerBusinessName (string) maxLength
            if (this.IssuerBusinessName != null && this.IssuerBusinessName.Length > 150)
            {
                yield return new ValidationResult("Invalid value for IssuerBusinessName, length must be less than 150.", new [] { "IssuerBusinessName" });
            }

            yield break;
        }
    }

}
